const rerankResults = $input.first().json.results;
const originalChunks = $('Postgres Vector Search').all();

const rerankedChunks = rerankResults.map(result => {
  const originalIndex = result.index;
  const original = originalChunks[originalIndex].json;
  return {
    json: {
      ...original,
      rerank_score: result.relevance_score
    }
  };
});

return rerankedChunks;

const chunks = $input.all();
const originalQuery = $('Webhook').first().json.body.query;

if (chunks.length === 0 || !chunks[0].json.chunk_text) {
  return [{ json: { context: "TIDAK ADA DOKUMEN YANG DITEMUKAN.", query: originalQuery, sources: [], max_rerank_score: 0 } }];
}

let contextText = "";
let maxScore = chunks[0].json.rerank_score || 0;

// Gabungkan chunks menjadi context string
const contextParts = chunks.map((item, i) => {
  const d = item.json;
  return `--- Sumber ${i+1}: ${d.doc_type} No. ${d.doc_number} Tahun ${d.doc_year}, Pasal ${d.pasal_number || 'N/A'} ---\n${d.chunk_text}`;
});

contextText = contextParts.join('\n\n');

return [{
  json: {
    query: originalQuery,
    context: contextText,
    max_rerank_score: maxScore,
    sources: chunks.map(c => ({
      doc_title: c.json.doc_title,
      doc_type: c.json.doc_type,
      doc_number: c.json.doc_number,
      doc_year: c.json.doc_year,
      pasal_number: c.json.pasal_number,
      source_url: c.json.source_url,
      similarity_score: c.json.similarity,
      rerank_score: c.json.rerank_score,
    }))
  }
}];

return [{
  json: {
    answer: `Maaf, dari hasil pemindaian di database perpajakan saya, pertanyaan Anda tampaknya tidak berkaitan dengan hukum pajak yang saya ketahui.`,
    query: $json.query,
    sources: []
  }
}];

